204	}
205	
206	// eslint-disable-next-line @typescript-eslint/no-explicit-any
207	type SqliteDb = { prepare(sql: string): any };
208	
209	function writeEvent(db: SqliteDb, p: WriteEventParams): void {
210	  db.prepare(`
211	    INSERT INTO events
212	      (ts, workflow_id, item_id, session_id, stage, phase, attempt,
213	       event_type, level, message, extra)
214	    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
215	  `).run(
216	    p.ts,
217	    p.workflowId,
218	    p.itemId,
219	    p.sessionId,
220	    p.stage,
221	    p.phase,
222	    p.attempt,
223	    p.eventType,
224	    p.level,
225	    p.message,
226	    p.extra ?? null,
227	  );
228	}
229	
230	function writePendingAttention(
231	  db: SqliteDb,
232	  workflowId: string,
233	  kind: string,
234	  payload: Record<string, unknown>,
235	  now: string,
236	): void {
237	  db.prepare(`
238	    INSERT INTO pending_attention (workflow_id, kind, payload, created_at)
239	    VALUES (?, ?, ?, ?)
240	  `).run(workflowId, kind, JSON.stringify(payload), now);
241	}
242	
243	// ---------------------------------------------------------------------------
244	// Internal: derive pending_attention kind from side-effect labels
245	// ---------------------------------------------------------------------------
246	
247	const PENDING_ATTENTION_LABELS: Record<string, string> = {
248	  'insert pending_attention{kind=bootstrap_failed}': 'bootstrap_failed',
249	  'insert pending_attention': 'awaiting_user_retry',
250	  'insert pending_attention{kind=revisit_limit}': 'revisit_limit',
251	  'insert pending_attention{kind=stage_needs_approval}': 'stage_needs_approval',
252	};
253	
254	function pendingAttentionKindFromEffects(
255	  sideEffects: readonly string[],
256	): string | null {
257	  for (const effect of sideEffects) {
258	    const kind = PENDING_ATTENTION_LABELS[effect];
259	    if (kind) return kind;
260	    // Fuzzy match for labels containing 'pending_attention'
261	    if (effect.includes('pending_attention') && effect.includes('insert')) {
262	      const m = /kind=([^}]+)/.exec(effect);
263	      return m ? m[1] : 'awaiting_user_retry';
264	    }
265	  }
266	  return null;
267	}
268	
269	// ---------------------------------------------------------------------------
270	// Internal: revisit counter (RC-3: per item_id + destination_phase pair)
271	// ---------------------------------------------------------------------------
272	
273	function countRevisitEvents(
274	  db: SqliteDb,
275	  itemId: string,
276	  destination: string,
277	): number {
278	  const row = db
279	    .prepare(`
280	      SELECT COUNT(*) AS cnt FROM events
281	       WHERE item_id = ?
282	         AND event_type = 'prepost.revisit'
283	         AND json_extract(extra, '$.destination') = ?
284	    `)
285	    .get(itemId, destination) as { cnt: number };
286	  return row.cnt;
287	}
288	
289	function insertRevisitEvent(
290	  db: SqliteDb,
291	  p: { workflowId: string; itemId: string; sessionId: string | null; stage: string; phase: string; attempt: number },
292	  destination: string,
293	  now: string,
294	): void {
295	  writeEvent(db, {
296	    ts: now,
297	    workflowId: p.workflowId,
298	    itemId: p.itemId,
299	    sessionId: p.sessionId,
300	    stage: p.stage,
301	    phase: p.phase,
302	    attempt: p.attempt,
303	    eventType: 'prepost.revisit',
304	    level: 'info',
305	    message: `goto to phase "${destination}"`,
306	    extra: JSON.stringify({ destination }),
307	  });
308	}
309	
310	// ---------------------------------------------------------------------------
311	// Internal: check all depends_on are complete
312	// ---------------------------------------------------------------------------
313	
314	function checkAllDepsComplete(db: SqliteDb, item: ItemRow): boolean {
315	  if (!item.depends_on) return true;
316	  let deps: string[];
317	  try {
318	    deps = JSON.parse(item.depends_on) as string[];
319	  } catch {
320	    return false;
321	  }
322	  if (deps.length === 0) return true;
323	  const placeholders = deps.map(() => '?').join(',');
324	  const rows = db
325	    .prepare(`SELECT status FROM items WHERE id IN (${placeholders})`)
326	    .all(...deps) as { status: string }[];
327	  return rows.length === deps.length && rows.every(r => r.status === 'complete');
328	}
329	
330	// ---------------------------------------------------------------------------
331	// Internal: compute retry decision from item + ctx
332	// ---------------------------------------------------------------------------
333	
334	type RetryOutcome =
335	  | { kind: 'retry'; mode: Exclude<RetryMode, 'awaiting_user'>; nextRetryCount: number }
336	  | { kind: 'exhausted' };
337	
338	function computeRetry(item: ItemRow, ctx: GuardContext): RetryOutcome {
339	  return computeRetryDecision({
340	    retryCount: item.retry_count,
341	    maxOuterRetries: ctx.maxOuterRetries ?? DEFAULT_MAX_OUTER_RETRIES,
342	    retryLadder: ctx.retryLadder ?? DEFAULT_RETRY_LADDER,
343	  });
344	}
345	
346	// ---------------------------------------------------------------------------
347	// Internal: select the concrete outcome for a conditional transition
348	// ---------------------------------------------------------------------------
349	
350	/** States that trigger cascade-blocking of dependents (AC-2). */
351	const CASCADE_TRIGGER_STATES = new Set<State>(['awaiting_user', 'blocked', 'abandoned']);
352	
353	/** States where an item is terminal for stage-completion purposes (AC-1). */
354	const STAGE_TERMINAL_STATES = new Set<string>(['complete', 'blocked', 'abandoned']);
355	
356	interface OutcomeSelection {
357	  to: State;
358	  sideEffects: readonly string[];
359	  newRetryCount?: number;
360	  retryMode?: Exclude<RetryMode, 'awaiting_user'>;
361	  newPhase?: string;
362	}
363	
364	/**
365	 * Evaluate guards for a conditional TransitionResult and return the
366	 * concrete outcome.
367	 *
368	 * This function is the authoritative guard implementation for every
369	 * conditional (State × Event) pair.  The TRANSITIONS table provides the
370	 * documented outcomes; this function implements the guards that select one.
371	 *
372	 * Called only from within a db.transaction() callback, so the db parameter
373	 * is the raw writer connection (safe to read from).
