function applyPendingSideEffects(
  db: SqliteDb,
  sideEffects: readonly string[],
  workflowId: string,
  itemId: string,
  stage: string,
  phase: string,
  now: string,
): void {
  const kind = pendingAttentionKindFromEffects(sideEffects);
  if (kind) {
    writePendingAttention(db, workflowId, kind, { item_id: itemId, stage, phase }, now);
  }
}

